// src/views/user/MyProfile/composables/useProfileData.js
import { ref, onMounted } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'

export function useProfileData() {
  // 扩展 resumeData 的初始结构
  const resumeData = ref({
    avatar: '',
    name: '',
    phone: '',
    email: '',
    location: '',
    jobStatus: '',
    workYears: '',
    expectedSalary: '',
    bio: '',
    skills: [],
    education: [],
    experience: []
  })

  const formData = ref({})
  const completionRate = ref(0)
  const isLoading = ref(false)
  const error = ref(null)

  const calculateCompletionRate = () => {
    const requiredFields = ['name', 'phone', 'email', 'location', 'bio']
    const completedFields = requiredFields.filter(field => resumeData.value[field])
    completionRate.value = Math.round((completedFields.length / requiredFields.length) * 100)
  }

  const fetchInitialData = async () => {
    isLoading.value = true
    error.value = null
    try {
      const response = await profile.getBasicInfo()
      console.log('Profile response:', response)

      if (response.data) {
        // 合并数据，保留现有字段
        resumeData.value = {
          ...resumeData.value,
          ...response.data
        }
        calculateCompletionRate()
      } else {
        throw new Error('获取资料失败：无数据返回')
      }
    } catch (err) {
      console.error('获取用户资料失败:', err)
      error.value = err.message || '获取用户资料失败'
      showToast(error.value, 'error')
    } finally {
      isLoading.value = false
    }
  }

  const updateResumeData = async (data) => {
    isLoading.value = true
    error.value = null
    try {
      console.log('准备更新的数据:', data)

      // 如果只更新了头像，不需要调用更新接口
      if (Object.keys(data).length === 1 && data.avatar) {
        // 直接更新本地数据
        resumeData.value = {
          ...resumeData.value,
          avatar: data.avatar
        }
        return true
      }

      // 构建要发送的数据对象
      const updateData = {
        name: data.name,
        phone: data.phone,
        email: data.email,
        location: data.location,
        bio: data.bio,
        profession: data.profession,
        company: data.company,
        position: data.position
      }

      // 移除空值
      Object.keys(updateData).forEach(key => {
        if (updateData[key] === undefined || updateData[key] === null || updateData[key] === '') {
          delete updateData[key]
        }
      })

      // 如果没有需要更新的数据，直接返回
      if (Object.keys(updateData).length === 0) {
        return true
      }

      console.log('发送到后端的数据:', updateData)

      const response = await profile.updateBasicInfo(updateData)
      console.log('Update response:', response)

      if (response.data) {
        // 更新本地数据
        resumeData.value = {
          ...resumeData.value,
          ...response.data
        }
        calculateCompletionRate()
        showToast('更新成功', 'success')
        return true
      }

      throw new Error(response.data?.message || '更新失败')
    } catch (err) {
      console.error('更新用户资料失败:', err)
      error.value = err.message || '更新用户资料失败'
      showToast(error.value, 'error')
      return false
    } finally {
      isLoading.value = false
    }
  }

  // 在组件挂载时获取数据
  onMounted(() => {
    fetchInitialData()
  })

  return {
    resumeData,
    formData,
    completionRate,
    loading: isLoading,  // 重命名避免冲突
    error,
    fetchInitialData,
    updateResumeData
  }
}
